export type DictationLevel = "beginner" | "intermediate" | "advanced";
export type DictationCategory =
  | "news"
  | "vlog"
  | "cartoon"
  | "drama"
  | "education"
  | "history"
  | "discovery"
  | "other";

export interface DictationSegment {
  idx: number;
  start: number;
  dur: number;
  hanzi: string;
}

export interface DictationVideo {
  id: string;
  youtubeId: string;
  title: string;
  titleVi?: string;
  level: DictationLevel;
  category: DictationCategory;
  description?: string;
  durationLabel?: string;
  thumbnail?: string;
  /** Phụ đề tiếng Trung dựng sẵn (curated). Khi có, trang Dictation sẽ
   * dùng luôn thay vì gọi edge function (giúp tránh việc YouTube chặn IP). */
  segments?: DictationSegment[];
  /** Bản dịch tiếng Việt dựng sẵn, cùng thứ tự với `segments`.
   * Sinh bằng `bun scripts/translate-dictation.ts <youtubeId>`. */
  translations?: string[];
  languageCode?: string;
  isAutoGenerated?: boolean;
}

